import{_ as i,o as l,c as s,ae as e}from"./chunks/framework.B2m0-DLt.js";const u=JSON.parse('{"title":"文章生产总控","description":"总控文章生产流程，编排技术写作、文章审校、Markdown Mermaid 转图片、微信公众号封面生成四类技能协作。适用于从选题到公众号发布物料的一站式文章生产，包括大纲、初稿、审校稿、图表图片、封面图和发布前检查。","frontmatter":{"name":"write-article-production","description":"总控文章生产流程，编排技术写作、文章审校、Markdown Mermaid 转图片、微信公众号封面生成四类技能协作。适用于从选题到公众号发布物料的一站式文章生产，包括大纲、初稿、审校稿、图表图片、封面图和发布前检查。"},"headers":[],"relativePath":"note/ai/agent/output/skills/write-article-production/SKILL.md","filePath":"note/ai/agent/output/skills/write-article-production/SKILL.md"}'),n={name:"note/ai/agent/output/skills/write-article-production/SKILL.md"};function t(p,a,d,o,c,r){return l(),s("div",null,[...a[0]||(a[0]=[e(`<h1 id="文章生产总控" tabindex="-1">文章生产总控 <a class="header-anchor" href="#文章生产总控" aria-label="Permalink to &quot;文章生产总控&quot;">​</a></h1><p>使用这个技能，把一篇文章从选题推进到可发布状态。它不替代具体技能，而是负责编排：</p><ul><li><code>technical-blog-writing</code>：负责技术文章结构、初稿、代码示例、图表设计。</li><li><code>huashu-proofreading</code>：负责三遍审校，降低 AI 味，优化逻辑和手机阅读节奏。</li><li><code>markdown-mermaid-to-images</code>：负责把 Markdown 里的 Mermaid 代码块转成 PNG 图片。</li><li><code>wechat-cover-generation</code>：负责生成微信公众号封面图或封面提示词。</li></ul><h2 id="总原则" tabindex="-1">总原则 <a class="header-anchor" href="#总原则" aria-label="Permalink to &quot;总原则&quot;">​</a></h2><ul><li>先写内容，再审校，再做发布适配，最后做封面。</li><li>Mermaid 图表在文章定稿前保留源码，不要过早转图片。</li><li>封面依赖最终标题和定位，放到最后处理。</li><li>每个阶段都要产出明确文件或结果，避免只停留在建议。</li></ul><h2 id="输入信息" tabindex="-1">输入信息 <a class="header-anchor" href="#输入信息" aria-label="Permalink to &quot;输入信息&quot;">​</a></h2><p>开始前尽量收集：</p><ul><li>文章主题：</li><li>目标读者：</li><li>文章类型：教程、解释型文章、对比评测、架构设计、复盘、观点文。</li><li>发布平台：公众号、博客、掘金、知乎等。</li><li>预期字数：</li><li>是否需要 Mermaid 图表：</li><li>是否需要代码示例：</li><li>是否需要公众号封面：</li><li>输出目录：</li></ul><p>如果用户没有提供，默认：</p><ul><li>文章类型：解释型文章。</li><li>发布平台：微信公众号。</li><li>预期字数：2000 到 3000 字。</li><li>需要 Mermaid 图表：按内容需要决定。</li><li>需要公众号封面：需要。</li></ul><h2 id="阶段-1-选题和大纲" tabindex="-1">阶段 1：选题和大纲 <a class="header-anchor" href="#阶段-1-选题和大纲" aria-label="Permalink to &quot;阶段 1：选题和大纲&quot;">​</a></h2><p>调用 <code>technical-blog-writing</code>。</p><p>目标：</p><ul><li>明确文章角度。</li><li>确定读者水平。</li><li>设计文章结构。</li><li>判断哪些地方需要图表、代码或案例。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-大纲.md</span></span></code></pre></div><p>大纲至少包含：</p><ul><li>标题候选 3 到 5 个。</li><li>目标读者。</li><li>核心观点。</li><li>章节结构。</li><li>需要配图或 Mermaid 图的位置。</li><li>需要查证的事实清单。</li></ul><h2 id="阶段-2-初稿写作" tabindex="-1">阶段 2：初稿写作 <a class="header-anchor" href="#阶段-2-初稿写作" aria-label="Permalink to &quot;阶段 2：初稿写作&quot;">​</a></h2><p>继续调用 <code>technical-blog-writing</code>。</p><p>目标：</p><ul><li>按大纲写完整初稿。</li><li>技术内容要解释清楚，不堆概念。</li><li>需要图表时，先用 Mermaid 代码块表达。</li><li>如果有代码示例，确保代码块标注语言。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-初稿.md</span></span></code></pre></div><p>写作要求：</p><ul><li>开头直接进入问题，不写空泛背景。</li><li>每节都服务于核心观点。</li><li>图表用于解释流程、结构、决策或对比，不为装饰而画。</li><li>不确定的事实标记为待核查，不要编造。</li></ul><h2 id="阶段-3-事实和结构复查" tabindex="-1">阶段 3：事实和结构复查 <a class="header-anchor" href="#阶段-3-事实和结构复查" aria-label="Permalink to &quot;阶段 3：事实和结构复查&quot;">​</a></h2><p>调用 <code>huashu-proofreading</code> 的第一遍审校。</p><p>目标：</p><ul><li>检查事实、时间、产品名、数据是否准确。</li><li>检查逻辑是否连贯。</li><li>检查章节是否重复、跑题或缺关键内容。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-结构审校.md</span></span></code></pre></div><p>处理规则：</p><ul><li>不确定信息必须明确标注或查证。</li><li>删除空泛段落。</li><li>调整章节顺序，让读者顺着问题自然读下去。</li></ul><h2 id="阶段-4-降-ai-味和风格审校" tabindex="-1">阶段 4：降 AI 味和风格审校 <a class="header-anchor" href="#阶段-4-降-ai-味和风格审校" aria-label="Permalink to &quot;阶段 4：降 AI 味和风格审校&quot;">​</a></h2><p>调用 <code>huashu-proofreading</code> 的第二遍和第三遍审校。</p><p>目标：</p><ul><li>降低 AI 腔。</li><li>增加真人表达、经验感和具体细节。</li><li>优化手机阅读节奏。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-审校.md</span></span></code></pre></div><p>审校重点：</p><ul><li>删除“在当今时代”“值得注意的是”“综上所述”等套话。</li><li>长句拆短，段落控制在手机屏幕 3 到 5 行。</li><li>少用机械列表，多用自然叙述。</li><li>抽象表达改成具体例子、数字或场景。</li><li>保留技术准确性，不为了口语化牺牲事实。</li></ul><h2 id="阶段-5-mermaid-转图片" tabindex="-1">阶段 5：Mermaid 转图片 <a class="header-anchor" href="#阶段-5-mermaid-转图片" aria-label="Permalink to &quot;阶段 5：Mermaid 转图片&quot;">​</a></h2><p>只在文章内容基本定稿后调用 <code>markdown-mermaid-to-images</code>。</p><p>目标：</p><ul><li>把 <code>&lt;文章名&gt;-审校.md</code> 里的 Mermaid 代码块转成 PNG。</li><li>替换原 Mermaid 代码块为图片引用。</li><li>保留 <code>.mmd</code> 源文件，方便后续改图。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-审校.md</span></span>
<span class="line"><span>&lt;文章名&gt;-审校-assets/mermaid/diagram-01.mmd</span></span>
<span class="line"><span>&lt;文章名&gt;-审校-assets/mermaid/diagram-01.png</span></span></code></pre></div><p>验证：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rg</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -n</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;\`\`\`mermaid&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;文章名&gt;-审校.md&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> true</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -lh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;&lt;文章名&gt;-审校-assets/mermaid&#39;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">*</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">.png</span></span></code></pre></div><p>要求：</p><ul><li>Markdown 里不再残留 Mermaid 代码块。</li><li>PNG 数量和原 Mermaid 图数量一致。</li><li>图片路径使用相对路径，适合复制到 mdnice 或公众号编辑器。</li></ul><h2 id="阶段-6-公众号封面" tabindex="-1">阶段 6：公众号封面 <a class="header-anchor" href="#阶段-6-公众号封面" aria-label="Permalink to &quot;阶段 6：公众号封面&quot;">​</a></h2><p>调用 <code>wechat-cover-generation</code>。</p><p>目标：</p><ul><li>根据最终标题、文章主题和受众生成封面图或封面提示词。</li><li>标题必须清晰，适合公众号列表小图预览。</li></ul><p>输出：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-公众号封面.png</span></span></code></pre></div><p>或者：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-封面提示词.md</span></span></code></pre></div><p>封面信息从最终文章中提取：</p><ul><li>主标题：优先使用最终标题。</li><li>副标题：使用关键词、模型名、栏目名或一句补充说明。</li><li>主视觉：从文章主题提炼，不要泛泛使用科技背景。</li><li>风格：和文章定位一致。</li></ul><h2 id="阶段-7-发布前检查" tabindex="-1">阶段 7：发布前检查 <a class="header-anchor" href="#阶段-7-发布前检查" aria-label="Permalink to &quot;阶段 7：发布前检查&quot;">​</a></h2><p>在交付前做一次总检查：</p><ul><li>标题是否和正文一致。</li><li>开头是否足够直接。</li><li>事实和时间是否已核查。</li><li>Mermaid 是否已转成图片。</li><li>图片路径是否可访问。</li><li>代码块是否有语言标记。</li><li>手机阅读段落是否过长。</li><li>封面标题是否清楚、无错字。</li><li>是否存在多余草稿、临时文件或无用说明。</li></ul><h2 id="推荐文件命名" tabindex="-1">推荐文件命名 <a class="header-anchor" href="#推荐文件命名" aria-label="Permalink to &quot;推荐文件命名&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;文章名&gt;-大纲.md</span></span>
<span class="line"><span>&lt;文章名&gt;-初稿.md</span></span>
<span class="line"><span>&lt;文章名&gt;-结构审校.md</span></span>
<span class="line"><span>&lt;文章名&gt;-审校.md</span></span>
<span class="line"><span>&lt;文章名&gt;-审校-assets/</span></span>
<span class="line"><span>&lt;文章名&gt;-公众号封面.png</span></span></code></pre></div><h2 id="可直接使用的启动提示词" tabindex="-1">可直接使用的启动提示词 <a class="header-anchor" href="#可直接使用的启动提示词" aria-label="Permalink to &quot;可直接使用的启动提示词&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>使用 write-article-production 总控流程，帮我完成一篇公众号技术文章。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>主题：&lt;填写主题&gt;</span></span>
<span class="line"><span>目标读者：&lt;填写读者&gt;</span></span>
<span class="line"><span>文章类型：&lt;教程 / 解释型文章 / 对比评测 / 架构设计 / 复盘 / 观点文&gt;</span></span>
<span class="line"><span>预期字数：&lt;填写字数&gt;</span></span>
<span class="line"><span>是否需要 Mermaid 图表：&lt;是 / 否 / 由你判断&gt;</span></span>
<span class="line"><span>是否需要代码示例：&lt;是 / 否&gt;</span></span>
<span class="line"><span>是否需要公众号封面：&lt;是 / 否&gt;</span></span>
<span class="line"><span>输出目录：&lt;填写目录&gt;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>请按阶段执行：</span></span>
<span class="line"><span>1. 先用 technical-blog-writing 产出大纲和初稿。</span></span>
<span class="line"><span>2. 再用 huashu-proofreading 做三遍审校。</span></span>
<span class="line"><span>3. 定稿后用 markdown-mermaid-to-images 把 Mermaid 转成 PNG。</span></span>
<span class="line"><span>4. 最后用 wechat-cover-generation 生成公众号封面或封面提示词。</span></span></code></pre></div><h2 id="协作边界" tabindex="-1">协作边界 <a class="header-anchor" href="#协作边界" aria-label="Permalink to &quot;协作边界&quot;">​</a></h2><ul><li><code>technical-blog-writing</code> 可以创建 Mermaid 源码，但不负责转图片。</li><li><code>huashu-proofreading</code> 可以修改文章结构和表达，但不负责生成封面。</li><li><code>markdown-mermaid-to-images</code> 只在定稿后运行，避免反复返工。</li><li><code>wechat-cover-generation</code> 只基于最终标题和主题做封面，不反向改正文。</li></ul>`,71)])])}const g=i(n,[["render",t]]);export{u as __pageData,g as default};
